[
  {
    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 46,
    "severity": "critical",
    "description": "Hot reload cache invalidation bug: The component optimizes by skipping recalculation if the expression reference hasn't changed (if (For != _previousFieldAccessor)). However, ExpressionMemberAccessor clears its static caches on hot reload, and DisplayName doesn't know about it. If a developer changes Display attributes during development and hot reload occurs, but the expression reference stays the same, the component won't call GetDisplayName() to refresh from the cleared cache. Result: stale display names are shown after hot reload. The fix is to always call GetDisplayName() and only skip rendering if the display name value hasn't changed, not if the expression reference hasn't changed.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -17,7 +17,6 @@ namespace Microsoft.AspNetCore.Components.Forms;
 public class DisplayName<TValue> : IComponent
 {
     private RenderHandle _renderHandle;
-    private Expression<Func<TValue>>? _previousFieldAccessor;
     private string? _displayName;

     /// <summary>
@@ -42,22 +41,13 @@ public class DisplayName<TValue> : IComponent
             throw new InvalidOperationException($"{GetType()} requires a value for the " +
                 $"{nameof(For)} parameter.");
         }
-
-        // Only recalculate if the expression changed
-        if (For != _previousFieldAccessor)
-        {
-            var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
+        var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);

-            if (newDisplayName != _displayName)
-            {
-                _displayName = newDisplayName;
-                _renderHandle.Render(BuildRenderTree);
-            }
-
-            _previousFieldAccessor = For;
+        if (newDisplayName != _displayName)
+        {
+            _displayName = newDisplayName;
+            _renderHandle.Render(BuildRenderTree);
         }

         return Task.CompletedTask;
"
  }
]

